import{_ as i,p as e,q as r,a1 as p}from"./framework-0c1009fb.js";const h={};function s(d,a){return e(),r("div",null,[...a[0]||(a[0]=[p('<h1 id="vdsxray" tabindex="-1"><a class="header-anchor" href="#vdsxray" aria-hidden="true">#</a> VDSXRAY</h1><h2 id="что-это-такое-и-с-чем-его-едят" tabindex="-1"><a class="header-anchor" href="#что-это-такое-и-с-чем-его-едят" aria-hidden="true">#</a> Что это такое и с чем его едят</h2><p>VDS по протоколу XRAY для поключения к компьютеру</p><p>Мы не размещаем свои сервера, а арендуем их у хостинг провайдера</p><p>На данный момент сервера находятся в этих регионах:</p><p>🇫🇮 Finland (eu-north)</p><p>🇳🇱 Netherlands (eu-west)</p><h2 id="сокращения" tabindex="-1"><a class="header-anchor" href="#сокращения" aria-hidden="true">#</a> Сокращения</h2><p>PROJECT BEAUTIFUL WORLD - Далее BW</p><p>VDS XRAY - Далее Xray: Программа для доступа к VDS который расположен за пределами РФ</p><p>TELEGRAM BOT - Далее TG BOT: Главный бот магазина BW</p><p>ЛИЧНЫЙ КАБИНЕТ - Далее ЛК</p><p>Денежные средства - Далее ДС: Ваши деньги которыми вы пополнии баланс ЛК для покупки доступа к Xray</p><h2 id="протоколы" tabindex="-1"><a class="header-anchor" href="#протоколы" aria-hidden="true">#</a> Протоколы</h2><p>Коротко о каждом протоколе Shadowsocks — легкий прокси-протокол, разработанный именно для обхода блокировок. Он не использует сложное шифрование, что помогает ему быть более быстрым. Часто используется в странах с жесткой цензурой.</p><p>VLESS и VMess — протоколы из экосистемы V2Ray. Они обеспечивают гибкость и позволяют обходить продвинутые блокировки, притворяясь обычным HTTPS-трафиком.</p><p>VLESS — облегченная версия, созданная для минимизации задержек, а VMess более универсальный.</p><h2 id="цены-и-тарифы" tabindex="-1"><a class="header-anchor" href="#цены-и-тарифы" aria-hidden="true">#</a> Цены и тарифы</h2><p>У нас представлено три тарифных плана и один тестовый</p><p>акция - первый месяц за пол цены</p><h3 id="_0-тестовыи-тарифныи-план" tabindex="-1"><a class="header-anchor" href="#_0-тестовыи-тарифныи-план" aria-hidden="true">#</a> 0. Тестовый тарифный план</h3><p>Предназначен для тестирования наших услуг и принятия решения о дальнейшем приобретении VDS</p><p>🛜 VDS XRAY 0️⃣</p><ul><li>Цена: бесплатно</li><li>Протокол: Shadowsocks</li><li>Сервер: Финляндия</li><li>Лимит трафика в день: 20 ГБ</li><li>Срок действия: 5 дней</li></ul><h3 id="_1-базовыи-тарифныи-план" tabindex="-1"><a class="header-anchor" href="#_1-базовыи-тарифныи-план" aria-hidden="true">#</a> 1. Базовый тарифный план</h3><p>Подходит для обычного использования услуг и простого серфинга в интернете</p><p>🛜 VDS XRAY 1️⃣</p><ul><li>Цена: 60₽</li><li>Протокол: Shadowsocks</li><li>Сервер: Финляндия</li><li>Лимит трафика в день: 60 ГБ</li><li>Срок действия: 1 месяц</li></ul><h3 id="_2-улучшенныи-тарифныи-план" tabindex="-1"><a class="header-anchor" href="#_2-улучшенныи-тарифныи-план" aria-hidden="true">#</a> 2. Улучшенный тарифный план</h3><p>Предназначен для тех, кто хочет использовать более защищённый протокол соединения</p><p>🛜 VDS XRAY 2️⃣</p><ul><li>Цена: 120₽</li><li>Протоколы: Shadowsocks, VMess</li><li>Сервер: Финляндия</li><li>Лимит трафика в день: 120 ГБ</li><li>Срок действия: 1 месяц</li></ul><h3 id="_3-максимальныи-тарифныи-план" tabindex="-1"><a class="header-anchor" href="#_3-максимальныи-тарифныи-план" aria-hidden="true">#</a> 3. Максимальный тарифный план</h3><p>Подходит для тех, кому нужно больше возможностей</p><p>🛜 VDS XRAY 3️⃣</p><ul><li>Цена: 240₽</li><li>Протоколы: Shadowsocks, VMess, VLess, Trojan</li><li>Сервера: Финляндия, Нидерланды</li><li>Лимит трафика в день: 240 ГБ</li><li>Срок действия: 1 месяц</li></ul><h2 id="как-подключиться-к-vdsxray" tabindex="-1"><a class="header-anchor" href="#как-подключиться-к-vdsxray" aria-hidden="true">#</a> Как подключиться к VDSXRAY</h2><p>Для подклчения вам нужно воспользоваться одной из программ которые есть для всех устройст</p><p>ссылку для подключение и QR код вы получите после оплаты услуги</p><h2 id="оплата-через-бота" tabindex="-1"><a class="header-anchor" href="#оплата-через-бота" aria-hidden="true">#</a> Оплата через бота</h2><p>Оплата в боте происходит через ЮMoney</p><p>После оплаты вы сможете приобресмти один из ключей для доступа в VDS</p><h2 id="полныи-гаид-покупки-через-бота" tabindex="-1"><a class="header-anchor" href="#полныи-гаид-покупки-через-бота" aria-hidden="true">#</a> Полный гайд покупки через бота</h2><p>Тут мы расписали полную инструкцию покупки VDS через нашего бота. В этом гайде мы не будем описывать все кнопки в боте</p><p>Некоторые скриншоты могут отличаться, мы работаем надо ботом и стараемся сделать его более понятным</p><h3 id="_1-запуск-бота" tabindex="-1"><a class="header-anchor" href="#_1-запуск-бота" aria-hidden="true">#</a> 1. Запуск бота</h3><p><img src="https://wiki.projectbw.ru/images/vdsxray/1.jpg" alt="VDS1"></p><p>Запустите бота в TG @ProjectBwShop_bot https://t.me/ProjectBwShop_bot</p><h3 id="_2-главное-меню" tabindex="-1"><a class="header-anchor" href="#_2-главное-меню" aria-hidden="true">#</a> 2. Главное меню</h3><p><img src="https://wiki.projectbw.ru/images/vdsxray/2.jpg" alt="VDS2"></p><p>После запуска бота вы увидите главное меню</p><ol><li><p>Баланс - показывает ваш баланс ЛК</p></li><li><p>Список VDS ключей - покажет ваш список услуг</p></li><li><p>Реф. система - приводи друзей и зарабатывай бонус</p></li><li><p>Помощь - гайды и Саппорт бот</p></li><li><p>О Нас -</p></li><li><p>Статистика -</p></li><li><p>Группа в ТГ -</p></li></ol><p>Как мы писали выше о всех кнопках в этом гайде мы не будем расказывать</p><p>Нажиите кнопку баланс</p><h3 id="_3-баланс-и-пополнение" tabindex="-1"><a class="header-anchor" href="#_3-баланс-и-пополнение" aria-hidden="true">#</a> 3. БАЛАНС И ПОПОЛНЕНИЕ</h3><p><img src="https://wiki.projectbw.ru/images/vdsxray/3.jpg" alt="VDS3"></p><p>Нажав баланс мы видим меню</p><ol><li><p>Пользовательское соглашение</p></li><li><p>Пополнить через</p></li><li><p>Пополнить через</p></li><li><p>История платежей</p></li><li><p>Назад</p></li></ol><p>Нам нужно нажать Пополнить через или Пополнить через и у нас отроется окно оплаты</p><p><img src="https://wiki.projectbw.ru/images/vdsxray/4.jpg" alt="VDS4"><img src="https://wiki.projectbw.ru/images/vdsxray/5.jpg" alt="VDS5"><img src="https://wiki.projectbw.ru/images/vdsxray/6.jpg" alt="VDS6"><img src="https://wiki.projectbw.ru/images/vdsxray/7.jpg" alt="VDS7"><img src="https://wiki.projectbw.ru/images/vdsxray/8.jpg" alt="VDS8"><img src="https://wiki.projectbw.ru/images/vdsxray/9.jpg" alt="VDS9"><img src="https://wiki.projectbw.ru/images/vdsxray/10.jpg" alt="VDS10"><img src="https://wiki.projectbw.ru/images/vdsxray/11.jpg" alt="VDS11"><img src="https://wiki.projectbw.ru/images/vdsxray/12.jpg" alt="VDS12"><img src="https://wiki.projectbw.ru/images/vdsxray/13.jpg" alt="VDS13"><img src="https://wiki.projectbw.ru/images/vdsxray/14.jpg" alt="VDS14"><img src="https://wiki.projectbw.ru/images/vdsxray/15.jpg" alt="VDS15"></p><h2 id="пользовательское-соглашение" tabindex="-1"><a class="header-anchor" href="#пользовательское-соглашение" aria-hidden="true">#</a> Пользовательское соглашение</h2><h3 id="при-пополнение-баланса" tabindex="-1"><a class="header-anchor" href="#при-пополнение-баланса" aria-hidden="true">#</a> При пополнение баланса</h3><p>При пополнении баланса вы соглашаетесь с &quot;Пользовательским соглащение&quot; Ваши ДС возврату не подлежат</p><h3 id="блокировки-от-ркн" tabindex="-1"><a class="header-anchor" href="#блокировки-от-ркн" aria-hidden="true">#</a> БЛОКИРОВКИ ОТ РКН</h3><p>При блокировках РФ BW не несет ответственности за ваши ДС</p><p>Со своей стороны мы стараемся потдерживать все протоколы подключения в доступе</p><h3 id="ответственость-за-vds" tabindex="-1"><a class="header-anchor" href="#ответственость-за-vds" aria-hidden="true">#</a> ОТВЕТСТВЕНОСТЬ ЗА VDS</h3><p>BW не несет отвечтвености за Ваши действия на XRAY</p><h3 id="пользовательское-соглашение-1" tabindex="-1"><a class="header-anchor" href="#пользовательское-соглашение-1" aria-hidden="true">#</a> ПОЛЬЗОВАТЕЛЬСКОЕ СОГЛАШЕНИЕ</h3>',69)])])}const l=i(h,[["render",s],["__file","index.html.vue"]]);export{l as default};
